// Extract configuration from request
const body = $input.item.json.body || $input.item.json;

// Default configuration
const config = {
  platforms: body.platforms || ['twitter', 'instagram', 'linkedin'],
  niche: body.niche || 'Technology & Innovation',
  trendSources: body.trendSources || ['twitter', 'reddit', 'google'],
  contentTypes: body.contentTypes || ['educational', 'entertaining', 'news'],
  targetAudience: body.targetAudience || 'tech-savvy professionals, 25-45',
  brandVoice: body.brandVoice || 'professional yet approachable',
  minTrendScore: parseInt(body.minTrendScore) || 60,
  maxIdeasPerTrend: parseInt(body.maxIdeasPerTrend) || 3,
  includeVisuals: Boolean(body.includeVisuals !== false),
  includeHashtags: Boolean(body.includeHashtags !== false),
  waitTimeSeconds: parseInt(body.waitTimeSeconds) || 120,
  analysisWaitSeconds: parseInt(body.analysisWaitSeconds) || 60
};

// Brand profile (customize per user)
const brandProfile = {
  name: body.brandName || 'YOUR_BRAND',
  industry: body.industry || config.niche,
  values: body.brandValues || ['innovation', 'authenticity', 'expertise'],
  prohibitedTopics: body.prohibitedTopics || ['politics', 'controversial'],
  preferredFormats: body.preferredFormats || ['carousel', 'infographic', 'video'],
  colorScheme: body.colorScheme || ['#0066CC', '#FF6B35', '#F7F7F7']
};

// Engagement patterns (historical data or defaults)
const engagementPatterns = {
  twitter: {
    peakHours: [9, 12, 17, 20],
    peakDays: ['Tuesday', 'Wednesday', 'Thursday'],
    avgEngagementRate: 0.03
  },
  instagram: {
    peakHours: [11, 13, 19, 21],
    peakDays: ['Wednesday', 'Friday', 'Sunday'],
    avgEngagementRate: 0.045
  },
  linkedin: {
    peakHours: [8, 12, 17],
    peakDays: ['Tuesday', 'Wednesday', 'Thursday'],
    avgEngagementRate: 0.02
  }
};

return {
  json: {
    config,
    brandProfile,
    engagementPatterns,
    metadata: {
      requestId: `SMTS-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      startedAt: new Date().toISOString(),
      timezone: body.timezone || 'Asia/Kolkata'
    }
  }
};

// Get configuration and trend data
const config = $('Validate Config & Build Parameters').first().json.config;
const brandProfile = $('Validate Config & Build Parameters').first().json.brandProfile;

const allTrends = [];

// Parse Twitter trends
const twitterData = $input.all().find(item => item.json.data?.trends);
if (twitterData) {
  const trends = twitterData.json.data.trends || [];
  trends.forEach(trend => {
    allTrends.push({
      source: 'twitter',
      topic: trend.name || trend.query,
      volume: trend.tweet_volume || 0,
      url: trend.url,
      rawScore: Math.min(100, (trend.tweet_volume || 0) / 1000)
    });
  });
}

// Parse Reddit trends
const redditData = $input.all().find(item => item.json.data?.children);
if (redditData) {
  const posts = redditData.json.data.children || [];
  posts.forEach(post => {
    const data = post.data;
    allTrends.push({
      source: 'reddit',
      topic: data.title,
      volume: data.ups + data.num_comments,
      url: `https://reddit.com${data.permalink}`,
      subreddit: data.subreddit,
      rawScore: Math.min(100, ((data.ups + data.num_comments) / 100))
    });
  });
}

// Parse Google Trends
const googleData = $input.all().find(item => item.json.default?.trendingSearchesDays);
if (googleData) {
  const trendDays = googleData.json.default.trendingSearchesDays || [];
  trendDays.forEach(day => {
    (day.trendingSearches || []).forEach(search => {
      allTrends.push({
        source: 'google',
        topic: search.title?.query || search.title,
        volume: parseInt(search.formattedTraffic?.replace(/[+,]/g, '')) || 0,
        url: search.articles?.[0]?.url || '',
        rawScore: Math.min(100, (parseInt(search.formattedTraffic?.replace(/[+,]/g, '')) || 0) / 10000)
      });
    });
  });
}

// Filter and score trends
const processedTrends = allTrends
  .filter(trend => {
    // Remove prohibited topics
    const topicLower = trend.topic.toLowerCase();
    return !brandProfile.prohibitedTopics.some(prohibited => 
      topicLower.includes(prohibited.toLowerCase())
    );
  })
  .map(trend => {
    // Calculate relevance score
    const nicheLower = config.niche.toLowerCase();
    const topicLower = trend.topic.toLowerCase();

    // Niche matching bonus
    const nicheWords = nicheLower.split(/\s+/);
    const nicheMatch = nicheWords.some(word => topicLower.includes(word)) ? 30 : 0;

    // Volume score (normalized)
    const volumeScore = trend.rawScore || 0;

    // Final score
    const finalScore = Math.min(100, volumeScore + nicheMatch);

    return {
      ...trend,
      nicheRelevance: nicheMatch,
      finalScore,
      timestamp: new Date().toISOString()
    };
  })
  .filter(trend => trend.finalScore >= config.minTrendScore)
  .sort((a, b) => b.finalScore - a.finalScore)
  .slice(0, 10); // Top 10 trends

if (processedTrends.length === 0) {
  throw new Error('No relevant trends found matching your niche and score threshold');
}

console.log(`Filtered ${processedTrends.length} relevant trends from ${allTrends.length} total`);

// Return each trend as separate item for parallel processing
return processedTrends.map(trend => ({
  json: {
    trend,
    config,
    brandProfile,
    metadata: $('Validate Config & Build Parameters').first().json.metadata
  }
}));

