const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle content array format from Anthropic
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Clean JSON from markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let generatedContent;
try {
  generatedContent = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse AI response: ${error.message}. Response was: ${cleanText.substring(0, 200)}...`);
}

// Get trend and config from upstream
const trendData = $('Parse & Filter Trending Topics').item.json;

return {
  json: {
    trend: trendData.trend,
    config: trendData.config,
    brandProfile: trendData.brandProfile,
    generatedIdeas: generatedContent.ideas || [],
    trendContext: generatedContent.trendContext,
    timingSensitivity: generatedContent.timingSensitivity || 'medium',
    generatedAt: new Date().toISOString(),
    metadata: trendData.metadata
  }
};

const data = $input.item.json;
const config = data.config;
const engagementPatterns = $('Validate Config & Build Parameters').first().json.engagementPatterns;
const timezone = data.metadata.timezone;

// Calculate optimal posting times for each platform and idea
const ideasWithTiming = data.generatedIdeas.map((idea, index) => {
  const platform = idea.platform;
  const patterns = engagementPatterns[platform] || engagementPatterns.twitter;

  // Get current date/time in user's timezone
  const now = new Date();
  const currentHour = now.getHours();
  const currentDay = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: timezone });

  // Find next optimal posting slot
  let recommendedTime;
  let daysUntilPost = 0;
  let foundSlot = false;

  // Check next 7 days for optimal slot
  for (let day = 0; day < 7 && !foundSlot; day++) {
    const checkDate = new Date(now);
    checkDate.setDate(checkDate.getDate() + day);
    const dayName = checkDate.toLocaleDateString('en-US', { weekday: 'long', timeZone: timezone });

    if (patterns.peakDays.includes(dayName)) {
      // Find next peak hour on this day
      for (const peakHour of patterns.peakHours) {
        if (day === 0 && peakHour <= currentHour) continue; // Skip past hours today

        checkDate.setHours(peakHour, 0, 0, 0);
        recommendedTime = checkDate.toISOString();
        daysUntilPost = day;
        foundSlot = true;
        break;
      }
    }
  }

  // Fallback: next peak hour on any day
  if (!recommendedTime) {
    const fallbackDate = new Date(now);
    fallbackDate.setDate(fallbackDate.getDate() + 1);
    fallbackDate.setHours(patterns.peakHours[0], 0, 0, 0);
    recommendedTime = fallbackDate.toISOString();
    daysUntilPost = 1;
  }

  // Calculate expected engagement score
  const baseEngagement = patterns.avgEngagementRate;
  const trendBoost = data.trend.finalScore / 100; // Trending topics boost engagement
  const timingSensitivityMultiplier = 
    data.timingSensitivity === 'high' ? 1.5 :
    data.timingSensitivity === 'medium' ? 1.2 : 1.0;

  const expectedEngagement = baseEngagement * (1 + trendBoost) * timingSensitivityMultiplier;

  // Format human-readable time
  const timeObj = new Date(recommendedTime);
  const formattedTime = timeObj.toLocaleString('en-US', {
    timeZone: timezone,
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true
  });

  return {
    ...idea,
    timing: {
      recommendedPostTime: recommendedTime,
      formattedTime,
      daysUntilPost,
      timezone,
      urgency: data.timingSensitivity === 'high' && daysUntilPost > 2 ? 'URGENT - Trend may fade' : 'optimal',
      expectedEngagementRate: (expectedEngagement * 100).toFixed(2) + '%',
      peakHours: patterns.peakHours,
      peakDays: patterns.peakDays
    },
    metadata: {
      ideaId: `${data.metadata.requestId}-idea-${index + 1}`,
      trendTopic: data.trend.topic,
      trendSource: data.trend.source,
      trendScore: data.trend.finalScore
    }
  };
});

// Summary statistics
const summary = {
  totalIdeas: ideasWithTiming.length,
  platformBreakdown: config.platforms.reduce((acc, platform) => {
    acc[platform] = ideasWithTiming.filter(i => i.platform === platform).length;
    return acc;
  }, {}),
  urgentIdeas: ideasWithTiming.filter(i => i.timing.urgency === 'URGENT - Trend may fade').length,
  avgExpectedEngagement: (
    ideasWithTiming.reduce((sum, i) => sum + parseFloat(i.timing.expectedEngagementRate), 0) / 
    ideasWithTiming.length
  ).toFixed(2) + '%',
  nextPostingWindow: ideasWithTiming[0]?.timing.formattedTime
};

return {
  json: {
    trendTopic: data.trend.topic,
    trendScore: data.trend.finalScore,
    trendSource: data.trend.source,
    trendContext: data.trendContext,
    timingSensitivity: data.timingSensitivity,
    contentIdeas: ideasWithTiming,
    summary,
    brandProfile: data.brandProfile,
    generatedAt: data.generatedAt,
    processedAt: new Date().toISOString(),
    requestId: data.metadata.requestId
  }
};

// Aggregate all processed ideas from all trends
const allResults = $input.all().map(item => item.json);

// Create comprehensive response
const response = {
  success: true,
  message: `Generated ${allResults.reduce((sum, r) => sum + r.contentIdeas.length, 0)} content ideas from ${allResults.length} trending topics`,
  trends: allResults.map(result => ({
    topic: result.trendTopic,
    score: result.trendScore,
    source: result.trendSource,
    context: result.trendContext,
    timingSensitivity: result.timingSensitivity,
    ideasCount: result.contentIdeas.length,
    ideas: result.contentIdeas
  })),
  summary: {
    totalTrends: allResults.length,
    totalIdeas: allResults.reduce((sum, r) => sum + r.contentIdeas.length, 0),
    platformsTargeted: [...new Set(allResults.flatMap(r => r.contentIdeas.map(i => i.platform)))],
    urgentPosts: allResults.reduce((sum, r) => 
      sum + r.contentIdeas.filter(i => i.timing.urgency.includes('URGENT')).length, 0
    ),
    nextPostingWindow: allResults[0]?.summary?.nextPostingWindow,
    generatedAt: allResults[0]?.generatedAt,
    requestId: allResults[0]?.requestId
  },
  recommendations: [
    "Review all ideas and select the ones that best match your brand voice",
    "Schedule urgent posts within 24-48 hours to capitalize on trend momentum",
    "Customize captions to add your unique brand personality",
    "Create or commission visuals based on the provided concepts",
    "Track performance and log results back to this system for better future recommendations"
  ]
};

return [{ json: response }];
